// Normaliza o CPF (só dígitos)
const body = $input.first().json.body || $input.first().json;
const cpf = String(body.cpf || '').replace(/\D/g, '');
return [{ json: { cpf } }];

// Soma a dívida vencida e calcula a quitação com 50% de desconto
const resp = $input.first().json;
const cobrancas = resp.data || [];
const clienteNode = $('Asaas — Buscar Cliente por CPF').first().json.data[0];

let total = 0;
for (const c of cobrancas) {
  total += Number(c.value || 0);
}

const valorDivida = total.toFixed(2);
const valorAVista = (total * 0.5).toFixed(2);
const encontrado = total > 0 ? 'true' : 'false';

const fmt = (n) => Number(n).toFixed(2).replace('.', ',');

return [{ json: {
  data: {
    encontrado,
    nome: (clienteNode.name || 'Cliente').split(' ')[0],
    nome_completo: clienteNode.name || '',
    customer_id: clienteNode.id,
    qtd_cobrancas: cobrancas.length,
    valor_divida: fmt(valorDivida),
    valor_a_vista_50: fmt(valorAVista),
    valor_divida_num: valorDivida,
    valor_a_vista_num: valorAVista
  }
} }];
